+        ) {
+            let left = asupersync::Budget::new().with_deadline(asupersync::Time::from_millis(left_ms));
+            let right = asupersync::Budget::new().with_deadline(asupersync::Time::from_millis(right_ms));
+            let combined = left.meet(right);
